import React, { useState, useEffect } from 'react';
import VendorForm from './VendorForm';
import { Vendor, getVendors, createVendor } from '../services/api';


const VendorTable: React.FC = () => {
  const [vendors, setVendors] = useState<Vendor[]>([]);
  const [showForm, setShowForm] = useState(false);
  const [editingVendor, setEditingVendor] = useState<Vendor | null>(null);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    setLoading(true);
    getVendors()
      .then(res => setVendors(res.data))
      .finally(() => setLoading(false));
  }, []);

  const handleAdd = () => {
    setEditingVendor(null);
    setShowForm(true);
  };

  const handleEdit = (vendor: Vendor) => {
    setEditingVendor(vendor);
    setShowForm(true);
  };

  const handleSave = async (vendor: Vendor) => {
    setLoading(true);
    try {
      if (editingVendor) {
        // Implement updateVendor if needed
      } else {
        const res = await createVendor(vendor);
        setVendors(prev => [...prev, res.data]);
      }
    } finally {
      setLoading(false);
      setShowForm(false);
    }
  };

  return (
    <div className="p-4">
      <div className="flex justify-between mb-4">
        <button onClick={handleAdd} className="px-4 py-2 bg-blue-600 text-white rounded">New Vendor</button>
      </div>
      <table className="min-w-full border rounded">
        <thead>
          <tr className="bg-gray-100">
            <th className="px-2 py-1 border">Name</th>
            <th className="px-2 py-1 border">Currency</th>
            <th className="px-2 py-1 border">Contact Person</th>
            <th className="px-2 py-1 border">Email</th>
            <th className="px-2 py-1 border">Phone</th>
            <th className="px-2 py-1 border">Website</th>
            <th className="px-2 py-1 border">Actions</th>
          </tr>
        </thead>
        <tbody>
          {vendors.map((vendor, idx) => (
            <tr key={idx} className="hover:bg-gray-50">
              <td className="px-2 py-1 border">{vendor.name}</td>
              <td className="px-2 py-1 border">{vendor.currency}</td>
              <td className="px-2 py-1 border">{vendor.contactPerson}</td>
              <td className="px-2 py-1 border">{vendor.email}</td>
              <td className="px-2 py-1 border">{vendor.phone}</td>
              <td className="px-2 py-1 border">{vendor.website}</td>
              <td className="px-2 py-1 border">
                <button onClick={() => handleEdit(vendor)} className="text-blue-600 hover:underline">Edit</button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
      {showForm && (
        <div className="fixed inset-0 flex items-center justify-center bg-black bg-opacity-30 z-50">
          <div className="bg-white rounded shadow-lg w-full max-w-2xl p-4">
            <VendorForm
              onSave={handleSave}
              onClose={() => setShowForm(false)}
              initialData={editingVendor || undefined}
            />
          </div>
        </div>
      )}
    </div>
  );
};

export default VendorTable;
